#ifndef nsSampleObserverService_h__
#define nsSampleObserverService_h__

#include "nsIObserverService.h"
#include "nsClassHashtable.h"
#include "nsCOMPtr.h"
#include "nsTArray.h"
#include "nsIObserver.h"

// {d4e5f6a7-b8c9-4123-0def-123456789abc}
#define NS_SAMPLEOBSERVERSERVICE_CID \
  { 0xd4e5f6a7, 0xb8c9, 0x4123, \
    { 0x0d, 0xef, 0x12, 0x34, 0x56, 0x78, 0x9a, 0xbc } }

#define NS_SAMPLEOBSERVERSERVICE_CONTRACTID \
  "@mozilla.org/sample-observer-service;1"

class nsSampleObserverService final : public nsIObserverService {
 public:
  NS_DECL_ISUPPORTS
  NS_DECL_NSIOBSERVERSERVICE

  nsSampleObserverService();

 private:
  ~nsSampleObserverService();

  nsClassHashtable<nsCStringHashKey, nsTArray<nsCOMPtr<nsIObserver>>>
      mObserverTable;
};

#endif  // nsSampleObserverService_h__
```

For the implementation:
```cpp
/* ... */
#include "nsSampleObserverService.h"
#include "mozilla/ModuleUtils.h"
#include "nsEnumeratorUtils.h"
#include "nsCOMArray.h"

NS_IMPL_ISUPPORTS(nsSampleObserverService, nsIObserverService)

NS_GENERIC_FACTORY_CONSTRUCTOR(nsSampleObserverService)

nsSampleObserverService::nsSampleObserverService() = default;
nsSampleObserverService::~nsSampleObserverService() = default;

NS_IMETHODIMP
nsSampleObserverService::AddObserver(nsIObserver* aObserver,
                                     const char* aTopic,
                                     bool aOwnsWeak) {
  if (!aObserver || !aTopic) {
    return NS_ERROR_INVALID_ARG;
  }
  nsTArray<nsCOMPtr<nsIObserver>>* observers =
      mObserverTable.GetOrInsertNew(nsDependentCString(aTopic));
  observers->AppendElement(aObserver);
  return NS_OK;
}

NS_IMETHODIMP
nsSampleObserverService::RemoveObserver(nsIObserver* aObserver,
                                        const char* aTopic) {
  if (!aObserver || !aTopic) {
    return NS_ERROR_INVALID_ARG;
  }
  nsTArray<nsCOMPtr<nsIObserver>>* observers =
      mObserverTable.Get(nsDependentCString(aTopic));
  if (!observers) {
    return NS_ERROR_FAILURE;
  }
  observers->RemoveElement(aObserver);
  return NS_OK;
}

NS_IMETHODIMP
nsSampleObserverService::NotifyObservers(nsISupports* aSubject,
                                         const char* aTopic,
                                         const char16_t* aData) {
  if (!aTopic) {
    return NS_ERROR_INVALID_ARG;
  }
  nsTArray<nsCOMPtr<nsIObserver>>* observers =
      mObserverTable.Get(nsDependentCString(aTopic));
  if (!observers) {
    return NS_OK;
  }
  // Snapshot the array to handle re-entrant notifications
  nsTArray<nsCOMPtr<nsIObserver>> snapshot(*observers);
  for (auto& observer : snapshot) {
    observer->Observe(aSubject, aTopic, aData);
  }
  return NS_OK;
}

NS_IMETHODIMP
nsSampleObserverService::EnumerateObservers(const char* aTopic,
                                            nsISimpleEnumerator** aResult) {
  if (!aTopic) {
    return NS_ERROR_INVALID_ARG;
  }
  nsCOMArray<nsISupports> array;
  nsTArray<nsCOMPtr<nsIObserver>>* observers =
      mObserverTable.Get(nsDependentCString(aTopic));
  if (observers) {
    for (auto& observer : *observers) {
      array.AppendObject(observer);
    }
  }
  return NS_NewArrayEnumerator(aResult, array, NS_GET_IID(nsIObserver));
}
```

