/*
 * nsSampleObserverService.h
 *
 * A sample XPCOM component implementing nsIObserverService.  Mirrors the
 * structure of the real nsObserverService (xpcom/ds/nsObserverService.h):
 *
 *   - CID macro following the {0x..., ...} brace-initialiser convention
 *   - NS_INLINE_DECL_STATIC_IID to embed the CID as a static constexpr kIID
 *   - NS_DECL_ISUPPORTS  – declares QueryInterface / AddRef / Release and the
 *                          nsAutoRefCnt mRefCnt member
 *   - NS_DECL_NSIOBSERVERSERVICE – declares all four IDL methods plus the
 *                                  noscript/notxpcom HasObservers helper
 *   - nsTHashtable<nsObserverList> for per-topic observer storage, matching
 *     the real implementation exactly
 *
 * Registration uses NS_GENERIC_FACTORY_CONSTRUCTOR (mozilla/ModuleUtils.h),
 * which synthesises nsSampleObserverServiceConstructor at the bottom of the
 * .cpp translation unit.
 */

#ifndef nsSampleObserverService_h_
#define nsSampleObserverService_h_

#include "nsIObserverService.h"  // NS_DECL_NSIOBSERVERSERVICE, nsIObserverService
#include "nsObserverList.h"      // nsObserverList (nsCharPtrHashKey entry type)
#include "nsTHashtable.h"        // nsTHashtable<>

// {A1B2C3D4-E5F6-7890-ABCD-EF0123456789}
//
