//
// AddRef/Release operate on the nsAutoRefCnt mRefCnt member declared by
// NS_DECL_ISUPPORTS in the header.  QueryInterface walks the interface table
// built from the variadic argument list.
// ---------------------------------------------------------------------------
NS_IMPL_ISUPPORTS(nsSampleObserverService, nsIObserverService)

// ---------------------------------------------------------------------------
// Constructor / Destructor
// ---------------------------------------------------------------------------

nsSampleObserverService::nsSampleObserverService() = default;

nsSampleObserverService::~nsSampleObserverService() {
  // Release all per-topic observer lists held in the hash table.
  mObserverTopicTable.Clear();
}

// ---------------------------------------------------------------------------
// nsIObserverService::AddObserver
//
// Registers aObserver for notifications on aTopic.  If aOwnsWeak is true and
// aObserver implements nsIWeakReference, a weak reference is stored; otherwise
// a strong reference is held.
//
// PutEntry either retrieves the existing nsObserverList for aTopic or inserts
// a new one, mirroring nsObserverService::AddObserver in nsObserverService.cpp.
// ---------------------------------------------------------------------------
NS_IMETHODIMP
nsSampleObserverService::AddObserver(nsIObserver* aObserver,
                                     const char* aTopic, bool aOwnsWeak) {
  if (NS_WARN_IF(!aObserver) || NS_WARN_IF(!aTopic)) {
    return NS_ERROR_INVALID_ARG;
  }

  nsObserverList* observerList = mObserverTopicTable.PutEntry(aTopic);
  if (!observerList) {
    return NS_ERROR_OUT_OF_MEMORY;
  }

  return observerList->AddObserver(aObserver, aOwnsWeak);
}

// ---------------------------------------------------------------------------
// nsIObserverService::RemoveObserver
//
// Unregisters aObserver from aTopic.  Returns NS_ERROR_FAILURE when no list
// exists for the topic, matching the real implementation.
// ---------------------------------------------------------------------------
NS_IMETHODIMP
nsSampleObserverService::RemoveObserver(nsIObserver* aObserver,
                                        const char* aTopic) {
  if (NS_WARN_IF(!aObserver) || NS_WARN_IF(!aTopic)) {
    return NS_ERROR_INVALID_ARG;
  }

  nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
  if (!observerList) {
    return NS_ERROR_FAILURE;
  }

  return observerList->RemoveObserver(aObserver);
}

// ---------------------------------------------------------------------------
// nsIObserverService::NotifyObservers
//
// Calls Observe(aSubject, aTopic, aSomeData) on every registered observer for
// aTopic.  nsObserverList::NotifyObservers clones the observer array in
// reverse-insertion order before iterating, so additions/removals during
// notification are safe.
// ---------------------------------------------------------------------------
NS_IMETHODIMP
nsSampleObserverService::NotifyObservers(nsISupports* aSubject,
                                         const char* aTopic,
                                         const char16_t* aSomeData) {
  if (NS_WARN_IF(!aTopic)) {
    return NS_ERROR_INVALID_ARG;
  }

  nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
  if (observerList) {
    observerList->NotifyObservers(aSubject, aTopic, aSomeData);
  }

  return NS_OK;
}

// ---------------------------------------------------------------------------
// nsIObserverService::EnumerateObservers
//
// Returns an nsISimpleEnumerator over all observers registered for aTopic.
// When no list exists, NS_NewEmptyEnumerator (nsEnumeratorUtils.h) is used,
// exactly as in nsObserverService::EnumerateObservers.
// ---------------------------------------------------------------------------
NS_IMETHODIMP
nsSampleObserverService::EnumerateObservers(const char* aTopic,
                                            nsISimpleEnumerator** aEnumerator) {
  if (NS_WARN_IF(!aEnumerator) || NS_WARN_IF(!aTopic)) {
    return NS_ERROR_INVALID_ARG;
  }

  nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
  if (!observerList) {
    return NS_NewEmptyEnumerator(aEnumerator);
  }

  observerList->GetObserverList(aEnumerator);
  return NS_OK;
}

// ---------------------------------------------------------------------------
// nsIObserverService::HasObservers  [noscript, notxpcom, nostdcall]
//
// Non-virtual C++ helper (not exposed to JS) that checks whether any observer
// is registered for aTopic.  nsTHashtable::Contains performs a hash lookup
// without allocating an entry.
// ---------------------------------------------------------------------------
bool nsSampleObserverService::HasObservers(const char* aTopic) {
  return mObserverTopicTable.Contains(aTopic);
}

